    T.FA_OWN_EMPE_ID = S.FA_OWN_EMPE_ID,
    T.OWN_FA_NUM_ENT_ENTP_ID = S.OWN_FA_NUM_ENT_ENTP_ID,
    T.ACAT_CNTRA_FIRM_CLRG_NUM = S.ACAT_CNTRA_FIRM_CLRG_NUM,
    T.ACAT_CNTRA_FIRM_NM = S.ACAT_CNTRA_FIRM_NM,
    T.ACAT_CNTRA_FIRM_SHRT_NM = S.ACAT_CNTRA_FIRM_SHRT_NM,
    T.ACAT_CNTRA_FIRM_CLRG_ID_TP_CD = S.ACAT_CNTRA_FIRM_CLRG_ID_TP_CD,
    T.MM_ALT_ID = S.MM_ALT_ID,
    T.AR_ORIG_SRC_STM_CD = S.AR_ORIG_SRC_STM_CD,
    T.SRC_STM_ID = S.SRC_STM_ID,
    T.SRC_STM_NM = S.SRC_STM_NM,
    T.SRC_CNCL_X_RVSN_CD = S.SRC_CNCL_X_RVSN_CD,
    T.SRC_OPT_CLSS_CD = S.SRC_OPT_CLSS_CD,
    T.TXN_RCNCL_REPL_CNT = S.TXN_RCNCL_REPL_CNT,
    T.TXN_RCNCL_ST_ID = S.TXN_RCNCL_ST_ID,
    T.TXN_RCNCL_ST_CD = S.TXN_RCNCL_ST_CD,
    T.TXN_RCNCL_ST_NM = S.TXN_RCNCL_ST_NM,
    T.MF_AC_NUM = S.MF_AC_NUM,
    T.OFST_ORIG_SRC_STM_AR_ID = S.OFST_ORIG_SRC_STM_AR_ID,
    T.OFST_AR_ORIG_SRC_STM_CD = S.OFST_AR_ORIG_SRC_STM_CD,
    T.OFST_AR_SETL_TP_CD = S.OFST_AR_SETL_TP_CD,
    T.OFST_AR_SETL_TP_DSC = S.OFST_AR_SETL_TP_DSC,
    T.AR_SETL_TP_CD = S.AR_SETL_TP_CD,
    T.AR_SETL_TP_DSC = S.AR_SETL_TP_DSC,
    T.ORIG_SRC_STM_AR_ID = S.ORIG_SRC_STM_AR_ID,
    T.TD_DIM_ID = S.TD_DIM_ID,
    T.EXG_DIM_ID = S.EXG_DIM_ID,
    T.ACG_TP_CD = S.ACG_TP_CD,
    T.ACG_TP_DIM_ID = S.ACG_TP_DIM_ID,
    T.ACG_TP_NM = S.ACG_TP_NM,
    T.ACG_TP_ID = S.ACG_TP_ID,
    T.ACTV_F = S.ACTV_F,
    T.AR_ID = S.AR_ID,
    T.BATCH_DT = S.BATCH_DT,
    T.BKG_DT = S.BKG_DT,
    T.BR_CD = S.BR_CD,
    T.BKR_AR_ID = S.BKR_AR_ID,
    T.BUY_SELL_IND = S.BUY_SELL_IND,
    T.CASH_AVY_CGY = S.CASH_AVY_CGY,
    T.CASH_SIMP_DSPL_AVY_CGY = S.CASH_SIMP_DSPL_AVY_CGY,
    T.CSH_AVY_CL_ID = S.CSH_AVY_CL_ID,
    T.CASH_AVY_TP = S.CASH_AVY_TP,
    T.CASH_SIMP_DSPL_AVY_TP = S.CASH_SIMP_DSPL_AVY_TP,
    T.CASH_ALT_DSC_TRAILER_2 = S.CASH_ALT_DSC_TRAILER_2,
    T.CASH_APA_EXT_QUALFR = S.CASH_APA_EXT_QUALFR,
    T.CSH_APA_ID = S.CSH_APA_ID,
    T.CASH_APA_TP_CD = S.CASH_APA_TP_CD,
    T.CASH_APA_TP_DSC = S.CASH_APA_TP_DSC,
    T.CSH_APA_TP_ID = S.CSH_APA_TP_ID,
    T.CASH_APA_TP_NM = S.CASH_APA_TP_NM,
    T.CASH_CIRD_PD_ID = S.CASH_CIRD_PD_ID,
    T.CASH_DB_CR_CD = S.CASH_DB_CR_CD,
    T.CASH_DB_CR_NM = S.CASH_DB_CR_NM,
    T.CASH_DSC_TRAILER_1 = S.CASH_DSC_TRAILER_1,
    T.CF_GEN_F = S.CF_GEN_F,
    T.CASH_POS_TP_CD = S.CASH_POS_TP_CD,
    T.CASH_POS_TP_DIM_ID = S.CASH_POS_TP_DIM_ID,
    T.CASH_POS_TP_NM = S.CASH_POS_TP_NM,
    T.CASH_POS_TP_ID = S.CASH_POS_TP_ID,
    T.CASH_PD_ID = S.CASH_PD_ID,
